import { d3_selectAll } from '../core/d3-constants';
import { bbox } from '../utils/zcutils';
import { createElement, applyFont } from '../utils/zcsvgutils';

export var getUserFontValue = function(fontStyle, userStyle) {
    var FONT_NORMAL = 'normal',
        style = (userStyle && userStyle['font-style']) || fontStyle['font-style'] || FONT_NORMAL,
        weight = (userStyle && userStyle['font-weight']) || fontStyle['font-weight'] || FONT_NORMAL,
        size = (userStyle && userStyle['font-size']) || fontStyle['font-size'],
        family = (userStyle && userStyle['font-family']) || fontStyle['font-family'];

    return `${style} ${FONT_NORMAL} ${weight} ${size} ${family}`;
};

export function getTextHeight(font) {
    let globalSvg = d3_selectAll('div.__baseZC_Container__ > svg.svgPattern');
    if (!globalSvg.node()) {
        globalSvg = createElement('svg', '.__zc_fakeBody', [1], d3_selectAll('body'));
    }
    let textElement = createElement('text', '#zc-text-dummy', [1], globalSvg);

    textElement.html('qtyplkjhgfd');
    applyFont(textElement, font);

    let height = bbox(textElement).height;
    textElement.remove();

    return height;
}
